  if (curr_offset < 0) {
    int xerrno = errno;

    /* Release the scoreboard. */
    lock.l_type = F_UNLCK;
    lock.l_whence = SEEK_SET;
    lock.l_start = 0;
    lock.l_len = 0;

    while (fcntl(fd, F_SETLKW, &lock) < 0) {
      if (errno == EINTR) {
        continue;
      }
    }

    /* Don't need the descriptor anymore. */
    (void) close(fd);

    errno = xerrno;
    return -1;
  }

